import redis
from functools import wraps

# Configuration
REDIS_NODES = ['redis-node1', 'redis-node2']
REDIS_PORT = 6379
SESSION_TTL = 3600  # 1 hour
API_KEY_TTL = 86400  # 1 day

def get_redis_client():
    return redis.RedisCluster(startup_nodes=REDIS_NODES, port=REDIS_PORT)

def cache_session(token):
    redis_client = get_redis_client()
    redis_client.setex(token, SESSION_TTL, token)
    return token

def cache_api_key(api_key):
    redis_client = get_redis_client()
    redis_client.setex(api_key, API_KEY_TTL, api_key)
    return api_key

if __name__ == "__main__":
    session_token = "session_12345"
    api_key = "api_key_67890"

    cached_session = cache_session(session_token)
    print(f"Cached Session Token: {cached_session}")

    cached_api_key = cache_api_key(api_key)
    print(f"Cached API Key: {cached_api_key}")